<script setup lang="ts">import { Code, Nav } from 'components'; import { RouterLink } from 'vue-router'
const navList = [{id:"sec-1",name:"概述"},{id:"sec-2",name:"关键属性"}]
const particleCode = `# GPUParticles2D ——代码控制粒子效果
@onready var particles: GPUParticles2D = $GPUParticles2D
func _ready() -> void:
    particles.emitting = false  # 默认不发射
func explode() -> void:
    particles.emitting = true   # 开始发射（one_shot=true 时一次性）
func start_continuous() -> void:
    particles.emitting = true   # 持续发射（one_shot=false）`
</script>
